+  const Matrix3f& R = tf.getRotation();
+  const Vec3f& T = tf.getTranslation();
+
+  Vec3f v_delta = R * e.radii;
+  bv.max_ = T + v_delta;
+  bv.min_ = T - v_delta;
+}
