-///           [a,b][c,d]+
-///           (c1c3'+c2c2'+c3c1')t^4+
-///           (c2c3'+c3c2')t^5+
-///           (c3c3')t^6+
-///           (c0+c1*t+c2*t^2+c3*t^3)[c,d]+
-///           (c0'+c1'*t+c2'*t^2+c3'*c^3)[a,b]
