-  FCL_REAL midSize = 0.5 * (tm.getTimeInterval()->t_[1] - tm.getTimeInterval()->t_[0]);
-  FCL_REAL midSize2 = midSize * midSize;
-  FCL_REAL midSize4 = midSize2 * midSize2;
