-    ucs[i].Sigma[0] = Vec3f(sigma, 0, 0);
-    ucs[i].Sigma[1] = Vec3f(0, sigma, 0);
-    ucs[i].Sigma[2] = Vec3f(0, 0, sigma);
-    */
-
-  }
-
