-        temp->next[coord] = current->hi;
-
-        current->hi->getVal()[coord] = new_max[coord];
-      }
-      else if (direction == 1)
-      {
-        //here, we first update the "hi" endpoint.
-        if(current->hi->next[coord] != NULL)
-        {
-          temp = current->hi;
-          while((temp->next[coord] != NULL) && (temp->getVal()[coord] < new_max[coord]))
