+fcl::CollisionObject* EnvironmentModelFCL::createGeom(const shapes::StaticShape *shape)
+{
+  fcl::CollisionObject* g = NULL;
+  switch(shape->type)
+  {
+  case shapes::PLANE:
+  {
+    // TODO: plane implementation
+    ROS_WARN_STREAM("Plane is not fully implemented using FCL yet");
+  }
+  break;
+  default:
+    break;
+  }
+  return g;
+}
