+  {
+    if(enable_contact)
+      is_collision = shapeIntersect(*model1, *model2, R1, T1, R2, T2, &contact_point, &penetration_depth, &normal);
+    else
+      is_collision = shapeIntersect(*model1, *model2, R1, T1, R2, T2);
+  }
