+  void relativeTransform(const Vec3f R1[3], const Vec3f& T1, const Vec3f R2[3], const Vec3f& T2, Vec3f R[3], Vec3f& T);
+
+  /** \brief compute eigen values and vectors */
+  void Meigen(Vec3f a[3], BVH_REAL dout[3], Vec3f vout[3]);
+
+
+}
