+void SSaPCollisionManager::setup()
+{
+  if(!setup_)
+  {
+    std::sort(objs_x.begin(), objs_x.end(), SortByXLow());
+    std::sort(objs_y.begin(), objs_y.end(), SortByYLow());
+    std::sort(objs_z.begin(), objs_z.end(), SortByZLow());
+    setup_ = true;
+  }
+}
